SourceCode.Declaration:
/// <summary>
/// Session-scoped registry of sales lines whose price was intentionally
/// edited by the user, so agreement-price preservation can let it through.
/// </summary>
final class ETGSalesLinePriceEditRegistry
{
    static Set registry;

}

Method.Source:
static Set instance()
{
    if (!registry)
    {
        registry = new Set(Types::Int64);
    }
    return registry;
}

static void clear(RecId _recId)
{
    Set s = ETGSalesLinePriceEditRegistry::instance();
    if (s.in(_recId))
    {
        s.remove(_recId);
    }
}
